#include <bits/stdc++.h>
using namespace std;
int n,m,mark[100005],a[100005];
vector<int> g[100005];
void bfs(int x){
    queue<int> b;
    b.push(x);
    while(b.size()){
        int f=b.front(),len=g[f].size();
        b.pop();
        for(int i=0;i<len;i++)
            if(a[g[f][i]]<x)
                a[g[f][i]]=x,b.push(g[f][i]);
    }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
        a[i]=i;
    for(int i=n;i;i--)
        bfs(i);
    for(int i=1;i<=n;i++)
        printf("%d ",a[i]);
    return 0;
}
